[CmdletBinding()]
param(
    [ValidateRange(1024, 65535)]
    [int]$Port = 8765,

    [string]$InstallRoot = (Join-Path $env:LOCALAPPDATA 'CosmicDream\Bridge'),

    [string]$TaskName = 'Cosmic Dream Bridge',

    [switch]$NoAutoStart,

    [switch]$NoLaunch
)

$ErrorActionPreference = 'Stop'
$payloads = [ordered]@{
    'CosmicDreamBridge.ps1' = ''
    'Install-CosmicDreamBridge.ps1' = ''
    'Uninstall-CosmicDreamBridge.ps1' = ''
}
$tempRoot = Join-Path ([System.IO.Path]::GetTempPath()) ("CosmicDreamBridge-{0}" -f [guid]::NewGuid().ToString('N'))

try {
    [void](New-Item -ItemType Directory -Path $tempRoot -Force)
    foreach ($entry in $payloads.GetEnumerator()) {
        $target = Join-Path $tempRoot $entry.Key
        [System.IO.File]::WriteAllBytes($target, [System.Convert]::FromBase64String($entry.Value))
    }
    $installParameters = @{
        Port = $Port
        InstallRoot = $InstallRoot
        TaskName = $TaskName
        NoAutoStart = $NoAutoStart
        NoLaunch = $NoLaunch
        Confirm = $false
    }
    & (Join-Path $tempRoot 'Install-CosmicDreamBridge.ps1') @installParameters
    if (-not $?) { throw 'Cosmic Dream Bridge installation failed.' }
} finally {
    if (Test-Path -LiteralPath $tempRoot) {
        $resolvedTemp = [System.IO.Path]::GetFullPath($tempRoot)
        $systemTemp = [System.IO.Path]::GetFullPath([System.IO.Path]::GetTempPath())
        if ($resolvedTemp.StartsWith($systemTemp, [System.StringComparison]::OrdinalIgnoreCase)) {
            Remove-Item -LiteralPath $resolvedTemp -Recurse -Force
        }
    }
}
